} from "@react-navigation/elements";
import React from "react";
import { Platform, StyleSheet } from "react-native";

export function HeaderButton({
  disabled,
  onPress,
  pressColor,
  pressOpacity,
  accessibilityLabel,
  testID,
  style,
  href,
  children,
}: HeaderButtonProps) {
