      behavior={Platform.OS === "ios" ? "padding" : undefined}
      keyboardVerticalOffset={80}
    >
      <Stack.Screen
        options={{
          headerTitle: () => {
            const dirName = thread.workDir
              ? thread.workDir.split("/").filter(Boolean).pop()
              : null;
            return (
              <View style={{ alignItems: "center" }}>
                <Text style={{ color: AC.label, fontSize: 16, fontWeight: "600" }} numberOfLines={1}>
                  {thread.title}
                </Text>
                {dirName ? (
                  <Text style={{ color: AC.systemGray, fontSize: 11, fontFamily: Platform.OS === "ios" ? "Menlo" : "monospace" }} numberOfLines={1}>
                    📁 {dirName}
                  </Text>
                ) : null}
              </View>
            );
          },
          headerRight: () => headerRight,
        }}
      />
      <View
        style={{
          paddingHorizontal: 16,
          paddingTop: 12,
          paddingBottom: bottom + 12,
          gap: 12,
          flex: 1,
        }}
      >
        <View
          style={{
            flex: 1,
            backgroundColor: AC.secondarySystemGroupedBackground,
            borderRadius: 18,
            borderColor: AC.separator,
            borderWidth: 1,
            overflow: "hidden",
          }}
        >
          {threadStatus === "running" && (
            <View
              style={{
                padding: 12,
                flexDirection: "row",
                alignItems: "center",
                gap: 8,
                borderBottomWidth: 1,
                borderBottomColor: AC.separator,
              }}
            >
              <ActivityIndicator />
              <Text style={{ color: AC.label }}>Assistant is running…</Text>
            </View>
          )}
          <FlatList
            ref={listRef}
            data={messages}
            keyExtractor={(item) => item.id}
            contentContainerStyle={{ padding: 16, gap: 12 }}
            renderItem={({ item }) => <MessageBubble message={item} />}
            ListEmptyComponent={() => (
              <View
                style={{
                  paddingVertical: 32,
                  alignItems: "center",
                  gap: 8,
                }}
              >
                <IconSymbol
                  name="ellipsis.bubble"
                  color={AC.systemGray2}
                  size={28}
                />
                <Text style={{ color: AC.systemGray }}>
                  No messages yet. Say hi!
                </Text>
              </View>
            )}
          />
        </View>

