function MessageBubble({ message }: { message: Message }) {
  const isUser = message.role === "user";
  const bubbleColor = isUser ? AC.label : AC.systemGray5;
  const textColor = isUser ? AC.systemBackground : AC.label;
  const [copied, setCopied] = useState(false);

  const onCopy = useCallback(async () => {
    await Clipboard.setStringAsync(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 1800);
  }, [message.content]);

  return (
    <View
      style={{
        flexDirection: "column",
        alignItems: isUser ? "flex-end" : "flex-start",
        gap: 4,
      }}
    >
      <View
        style={{
          maxWidth: "82%",
          backgroundColor: bubbleColor,
          borderRadius: 18,
          paddingHorizontal: 14,
          paddingVertical: 10,
          borderBottomLeftRadius: isUser ? 18 : 6,
          borderBottomRightRadius: isUser ? 6 : 18,
        }}
      >
        <Text style={{ color: textColor, fontSize: 15, lineHeight: 20 }}>
          {message.content}
        </Text>
      </View>

      <TouchableBounce sensory onPress={onCopy}>
        <View
          style={{
            flexDirection: "row",
            alignItems: "center",
            gap: 4,
            paddingHorizontal: 8,
            paddingVertical: 4,
            borderRadius: 8,
            backgroundColor: copied
              ? AC.systemGreen
              : AC.tertiarySystemGroupedBackground,
          }}
        >
          <IconSymbol
            name={copied ? "checkmark" : "doc.on.doc"}
            size={11}
            color={copied ? AC.systemBackground : AC.systemGray}
          />
          <Text
            style={{
              fontSize: 11,
              color: copied ? AC.systemBackground : AC.systemGray,
            }}
          >
            {copied ? "Copied" : "Copy"}
          </Text>
        </View>
      </TouchableBounce>
    </View>
  );
}
